"""ic_training_records.py -- training record management for IC certification."""
from dataclasses import dataclass, field
from datetime import date
from typing import Optional
import yaml


@dataclass
class TrainingEvent:
    event_type: str  # fundamentals | tabletop | shadow | solo_observed | quarterly_drill
    completed_date: date
    trainer: str
    passed: bool
    score: Optional[float] = None  # 0-100 for scored events
    notes: str = ""


@dataclass
class ICTrainingRecord:
    person_id: str
    name: str
    team: str
    events: list[TrainingEvent] = field(default_factory=list)

    def is_certified(self) -> bool:
        required = {"fundamentals", "tabletop", "shadow", "solo_observed"}
        passed_types = {
            e.event_type for e in self.events if e.passed
        }
        return required.issubset(passed_types)

    def latest_drill(self) -> Optional[date]:
        drills = [e for e in self.events if e.event_type == "quarterly_drill" and e.passed]
        return max((e.completed_date for e in drills), default=None)

    def needs_recertification(self, recert_months: int = 12) -> bool:
        from datetime import date
        from dateutil.relativedelta import relativedelta
        passed_solos = [e for e in self.events if e.event_type == "solo_observed" and e.passed]
        if not passed_solos:
            return True
        latest = max(e.completed_date for e in passed_solos)
        return date.today() > latest + relativedelta(months=recert_months)

    def days_since_last_drill(self) -> Optional[int]:
        latest = self.latest_drill()
        if latest is None:
            return None
        return (date.today() - latest).days


def load_records(path: str = "training-records/ic-records.yaml") -> list[ICTrainingRecord]:
    with open(path) as f:
        raw = yaml.safe_load(f)
    records = []
    for r in raw["records"]:
        events = [
            TrainingEvent(
                event_type=e["type"],
                completed_date=e["date"],
                trainer=e["trainer"],
                passed=e["passed"],
                score=e.get("score"),
                notes=e.get("notes", ""),
            )
            for e in r.get("events", [])
        ]
        records.append(ICTrainingRecord(
            person_id=r["id"],
            name=r["name"],
            team=r["team"],
            events=events,
        ))
    return records


if __name__ == "__main__":
    records = load_records()
    for rec in records:
        status = "CERTIFIED" if rec.is_certified() else "IN TRAINING"
        recert = " (RECERT DUE)" if rec.needs_recertification() else ""
        drill_days = rec.days_since_last_drill()
        drill_note = f" | Last drill: {drill_days}d ago" if drill_days else ""
        print(f"{rec.name}: {status}{recert}{drill_note}")
